import { useState } from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

// Map weather condition names to emoji
const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  if (conditionLower.includes('hail')) return '🧊';
  return '🌤️'; // default fallback
};

export default function GeneratedComponent(props: Props) {
  const weatherEmoji = getWeatherEmoji(props.condition);

  return (
    <Card padding={24} shadow="md" border>
      <Stack direction="vertical" gap={24}>
        {/* Header with city name */}
        <Stack direction="horizontal" justify="between" align="center">
          <Text variant="h2" color="var(--ggui-color-onSurface)">{props.city}</Text>
        </Stack>

        {/* Current weather section */}
        <Stack direction="horizontal" align="center" gap={24}>
          {/* Temperature and condition */}
          <Stack direction="vertical" gap={8} align="start">
            {/* Large temperature display */}
            <div style={{
              fontSize: '4rem',
              fontWeight: 'bold',
              color: 'var(--ggui-color-primary-600)',
              lineHeight: 1,
            }}>
              {props.temperature}°{props.unit}
            </div>

            {/* Condition with emoji */}
            <Stack direction="horizontal" gap={8} align="center">
              <span style={{ fontSize: '2rem' }}>{weatherEmoji}</span>
              <Text variant="body" color="var(--ggui-color-onSurface)" weight="medium">
                {props.condition}
              </Text>
            </Stack>
          </Stack>

          {/* Current conditions details */}
          <Stack direction="vertical" gap={12} align="start" justify="start">
            {/* Humidity */}
            <Stack direction="horizontal" gap={12} align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                Humidity
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface)" weight="bold">
                {props.humidity}%
              </Text>
            </Stack>

            {/* Wind speed */}
            <Stack direction="horizontal" gap={12} align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                Wind Speed
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurface)" weight="bold">
                {props.windSpeed} {props.unit === 'F' ? 'mph' : 'km/h'}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* Divider */}
        <div style={{
          height: '1px',
          backgroundColor: 'var(--ggui-color-outline)',
          margin: '0',
        }} />

        {/* 5-day forecast strip */}
        <Stack direction="vertical" gap={12}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="semibold">
            5-DAY FORECAST
          </Text>

          <Stack direction="horizontal" gap={8} wrap>
            {props.forecast.map((day, index) => (
              <Box
                key={index}
                padding={12}
                borderRadius="var(--ggui-shape-radius-md)"
                style={{
                  flex: '1 1 auto',
                  minWidth: '100px',
                  backgroundColor: 'var(--ggui-color-surfaceVariant)',
                  textAlign: 'center',
                  border: '1px solid var(--ggui-color-outline)',
                }}
              >
                <Stack direction="vertical" gap={8} align="center">
                  {/* Day name */}
                  <Text variant="label" color="var(--ggui-color-onSurface)" weight="semibold">
                    {day.day}
                  </Text>

                  {/* Weather icon */}
                  <span style={{ fontSize: '1.5rem' }}>
                    {day.icon}
                  </span>

                  {/* High/Low temps */}
                  <Stack direction="horizontal" gap={6} align="center" justify="center">
                    <Text variant="caption" color="var(--ggui-color-onSurface)" weight="bold">
                      {day.high}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Icon,
  Badge,
  Divider,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Element {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  electronConfiguration: string;
  row: number;
  col: number;
}

interface Props {
  elements: Array<{
    atomicNumber: number;
    symbol: string;
    name: string;
    atomicWeight: number;
    category: string;
    electronConfiguration: string;
    row: number;
    col: number;
  }>;
}

const CATEGORY_COLORS: Record<string, { bg: string; text: string; badge: string }> = {
  'Alkali Metals': {
    bg: 'var(--ggui-color-primary-50, #f0f9ff)',
    text: 'var(--ggui-color-primary-900, #0c4a6e)',
    badge: 'primary',
  },
  'Alkaline Earth Metals': {
    bg: 'var(--ggui-color-warning-100, #fef3c7)',
    text: 'var(--ggui-color-warning-900, #78350f)',
    badge: 'warning',
  },
  'Transition Metals': {
    bg: 'var(--ggui-color-primary-100, #e0f2fe)',
    text: 'var(--ggui-color-primary-800, #075985)',
    badge: 'info',
  },
  'Post-transition Metals': {
    bg: 'var(--ggui-color-neutral-100, #f3f4f6)',
    text: 'var(--ggui-color-onSurface, #18181b)',
    badge: 'secondary',
  },
  'Metalloids': {
    bg: 'var(--ggui-color-warning-50, #fffbeb)',
    text: 'var(--ggui-color-warning-900, #78350f)',
    badge: 'warning',
  },
  'Nonmetals': {
    bg: 'var(--ggui-color-error-50, #fef2f2)',
    text: 'var(--ggui-color-error-900, #7f1d1d)',
    badge: 'error',
  },
  'Halogens': {
    bg: 'var(--ggui-color-error-100, #fee2e2)',
    text: 'var(--ggui-color-error-800, #991b1b)',
    badge: 'error',
  },
  'Noble Gases': {
    bg: 'var(--ggui-color-success-50, #f0fdf4)',
    text: 'var(--ggui-color-success-900, #14532d)',
    badge: 'success',
  },
  'Lanthanides': {
    bg: 'var(--ggui-color-primary-200, #bae6fd)',
    text: 'var(--ggui-color-primary-900, #0c4a6e)',
    badge: 'primary',
  },
  'Actinides': {
    bg: 'var(--ggui-color-primary-300, #7dd3fc)',
    text: 'var(--ggui-color-primary-900, #0c4a6e)',
    badge: 'primary',
  },
};

const getCategoryColor = (category: string) => {
  return CATEGORY_COLORS[category] || {
    bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
    badge: 'default',
  };
};

export default function PeriodicTable({ elements }: Props) {
  const { motionEnabled } = useMotion();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(query) ||
        el.symbol.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    const cats = new Set(elements.map((el) => el.category));
    return Array.from(cats).sort();
  }, [elements]);

  const gridElements = useMemo(() => {
    const grid: Record<string, Element> = {};
    filteredElements.forEach((el) => {
      const key = String(el.row) + '-' + String(el.col);
      grid[key] = el;
    });
    return grid;
  }, [filteredElements]);

  const maxRow = Math.max(...elements.map((el) => el.row), 7);
  const maxCol = Math.max(...elements.map((el) => el.col), 18);

  const ElementCell = ({ element }: { element: Element }) => {
    const colors = getCategoryColor(element.category);
    return (
      <button
        onClick={() => setSelectedElement(element)}
        style={{
          backgroundColor: colors.bg,
          color: colors.text,
          border: '2px solid var(--ggui-color-outline, #d4d4d8)',
          borderRadius: 'var(--ggui-shape-radius-md, 8px)',
          padding: 'var(--ggui-spacing-2, 8px)',
          cursor: 'pointer',
          minHeight: '80px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          position: 'relative',
          transition: transition.transform + ', ' + transition.colors,
          fontFamily: 'var(--ggui-font-family, system-ui)',
        }}
        onMouseEnter={(e) => {
          (e.currentTarget as HTMLElement).style.transform = 'scale(1.05)';
          (e.currentTarget as HTMLElement).style.boxShadow =
            'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
        }}
        onMouseLeave={(e) => {
          (e.currentTarget as HTMLElement).style.transform = 'scale(1)';
          (e.currentTarget as HTMLElement).style.boxShadow = 'none';
        }}
      >
        <span
          style={{
            position: 'absolute',
            top: 'var(--ggui-spacing-1, 4px)',
            left: 'var(--ggui-spacing-1, 4px)',
            fontSize: 'var(--ggui-font-size-xs, 12px)',
            fontWeight: 'var(--ggui-font-weight-semibold, 600)',
            opacity: 0.7,
          }}
        >
          {element.atomicNumber}
        </span>
        <span
          style={{
            fontSize: 'var(--ggui-font-size-xl, 20px)',
            fontWeight: 'var(--ggui-font-weight-bold, 700)',
          }}
        >
          {element.symbol}
        </span>
        <span
          style={{
            fontSize: 'var(--ggui-font-size-xs, 12px)',
            opacity: 0.8,
            marginTop: 'var(--ggui-spacing-1, 4px)',
          }}
        >
          {element.atomicWeight.toFixed(2)}
        </span>
      </button>
    );
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding={24}>
        <Stack direction="vertical" gap={24}>
          <div style={{ animation: motionEnabled ? animation.slideInUp : 'none' }}>
            <Text variant="h1">Interactive Periodic Table</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Click on any element to view detailed information
            </Text>
          </div>

          <div style={{ animation: motionEnabled ? animation.slideInUp + ' 100ms' : 'none' }}>
            <Input placeholder="Search..." value={searchQuery} onChange={setSearchQuery} label="Search" />
          </div>

          <div style={{ animation: motionEnabled ? animation.slideInUp + ' 200ms' : 'none' }}>
            <Card padding={16} border>
              <Stack direction="vertical" gap={12}>
                <Text variant="h3" weight="semibold">
                  Legend
                </Text>
                <div
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                    gap: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  {categories.map((category) => {
                    const colors = getCategoryColor(category);
                    return (
                      <Row key={category} gap={12} align="center">
                        <div
                          style={{
                            width: '24px',
                            height: '24px',
                            borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                            backgroundColor: colors.bg,
                            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                          }}
                        />
                        <Text variant="body" color={colors.text}>
                          {category}
                        </Text>
                      </Row>
                    );
                  })}
                </div>
              </Stack>
            </Card>
          </div>

          <div style={{ animation: motionEnabled ? animation.slideInUp + ' 300ms' : 'none' }}>
            <Card padding={20} border shadow="md">
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(18, 1fr)',
                  gap: 'var(--ggui-spacing-2, 8px)',
                  minHeight: maxRow * 100 + 'px',
                }}
              >
                {Array.from({ length: maxRow }).map((_, row) =>
                  Array.from({ length: maxCol }).map((_, col) => {
                    const r = row + 1;
                    const c = col + 1;
                    const key = String(r) + '-' + String(c);
                    const element = gridElements[key];
                    return (
                      <div
                        key={key}
                        style={{
                          gridColumn: c,
                          gridRow: r,
                          opacity: element ? 1 : 0,
                          pointerEvents: element ? 'auto' : 'none',
                          animation:
                            element && motionEnabled
                              ? animation.scaleIn + ' 300ms ease-out'
                              : 'none',
                        }}
                      >
                        {element && <ElementCell element={element} />}
                      </div>
                    );
                  })
                )}
              </div>
            </Card>
          </div>

          {selectedElement && (
            <div style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
              <Card padding={24} border shadow="lg" style={{ position: 'relative' }}>
                <Stack direction="vertical" gap={16}>
                  <Row justify="between" align="center">
                    <Text variant="h2">{selectedElement.name}</Text>
                    <button
                      onClick={() => setSelectedElement(null)}
                      style={{
                        background: 'none',
                        border: 'none',
                        cursor: 'pointer',
                        fontSize: 'var(--ggui-font-size-2xl, 24px)',
                        color: 'var(--ggui-color-onSurface, #18181b)',
                        padding: 'var(--ggui-spacing-2, 8px)',
                      }}
                    >
                      <Icon name="x" size={24} />
                    </button>
                  </Row>

                  <Divider />

                  <div
                    style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                      gap: 'var(--ggui-spacing-4, 16px)',
                    }}
                  >
                    <div>
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        weight="semibold"
                      >
                        Symbol
                      </Text>
                      <Text
                        variant="h2"
                        color="var(--ggui-color-primary-600, #0284c7)"
                      >
                        {selectedElement.symbol}
                      </Text>
                    </div>

                    <div>
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        weight="semibold"
                      >
                        Atomic Number
                      </Text>
                      <Text variant="body" weight="bold">
                        {selectedElement.atomicNumber}
                      </Text>
                    </div>

                    <div>
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        weight="semibold"
                      >
                        Atomic Weight
                      </Text>
                      <Text variant="body" weight="bold">
                        {selectedElement.atomicWeight.toFixed(3)} u
                      </Text>
                    </div>

                    <div>
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        weight="semibold"
                      >
                        Category
                      </Text>
                      <div style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
                        <Badge variant={getCategoryColor(selectedElement.category).badge as any}>
                          {selectedElement.category}
                        </Badge>
                      </div>
                    </div>
                  </div>

                  <div>
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      weight="semibold"
                    >
                      Electron Configuration
                    </Text>
                    <Text
                      variant="body"
                      style={{
                        marginTop: 'var(--ggui-spacing-2, 8px)',
                        padding: 'var(--ggui-spacing-2, 8px)',
                        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        fontFamily: 'monospace',
                        wordBreak: 'break-word',
                      }}
                    >
                      {selectedElement.electronConfiguration}
                    </Text>
                  </div>

                  <Divider />

                  <Row gap={32} justify="start">
                    <div>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        Position
                      </Text>
                      <Text variant="body" weight="medium">
                        Row {selectedElement.row}, Column {selectedElement.col}
                      </Text>
                    </div>
                  </Row>
                </Stack>
              </Card>
            </div>
          )}

          {filteredElements.length === 0 && (
            <Card padding={48} border shadow="sm">
              <Stack direction="vertical" gap={12} align="center" justify="center">
                <Icon name="search" size={48} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                <Text
                  variant="h3"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  No elements found
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  Try searching for a different element name or symbol
                </Text>
              </Stack>
            </Card>
          )}

          {searchQuery && filteredElements.length > 0 && (
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Showing {filteredElements.length} of {elements.length} elements
            </Text>
          )}
        </Stack>
      </Container>
    </>
  );
}

import { useState } from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const weatherEmojis: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  snowy: '❄️',
  stormy: '⛈️',
  partly_cloudy: '⛅',
  foggy: '🌫️',
  windy: '💨',
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  const conditionKey = condition.toLowerCase().replace(/\s+/g, '_');
  const weatherIcon = weatherEmojis[conditionKey] || '🌤️';

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City */}
        <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)">
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16} align="center">
          {/* Temperature - Large and Prominent */}
          <div
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-primary-700, #0369a1)',
              lineHeight: '1',
            }}
          >
            {temperature}°{unit}
          </div>

          {/* Weather Condition with Icon */}
          <Row gap={12} align="center" justify="center">
            <span style={{ fontSize: '48px' }}>{weatherIcon}</span>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-800, #075985)"
              weight="semibold"
            >
              {condition}
            </Text>
          </Row>
        </Stack>

        {/* Current Conditions Grid */}
        <Row gap={16} justify="center" wrap>
          {/* Humidity */}
          <Box
            padding={12}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            background="var(--ggui-color-primary-100, #e0f2fe)"
          >
            <Stack direction="vertical" gap={4} align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="medium"
              >
                Humidity
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="bold"
              >
                {humidity}%
              </Text>
            </Stack>
          </Box>

          {/* Wind Speed */}
          <Box
            padding={12}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            background="var(--ggui-color-primary-100, #e0f2fe)"
          >
            <Stack direction="vertical" gap={4} align="center">
              <Text
                variant="caption"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="medium"
              >
                Wind Speed
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="bold"
              >
                {windSpeed} km/h
              </Text>
            </Stack>
          </Box>
        </Row>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-primary-200, #bae6fd)',
            margin: 'var(--ggui-spacing-2, 8px) 0',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="h3"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          <Row gap={8} wrap justify="start">
            {forecast.map((day, index) => (
              <Box
                key={index}
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background="var(--ggui-color-primary-50, #f0f9ff)"
                style={{
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                  minWidth: '100px',
                  textAlign: 'center',
                }}
              >
                <Stack direction="vertical" gap={8} align="center">
                  {/* Day Name */}
                  <Text
                    variant="label"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    weight="medium"
                  >
                    {day.day}
                  </Text>

                  {/* Weather Icon */}
                  <span style={{ fontSize: '32px' }}>{day.icon}</span>

                  {/* High/Low Temps */}
                  <Stack direction="horizontal" gap={8} justify="center">
                    <Text
                      variant="body"
                      color="var(--ggui-color-primary-900, #0c4a6e)"
                      weight="semibold"
                    >
                      {day.high}°
                    </Text>
                    <Text
                      variant="body"
                      color="var(--ggui-color-primary-600, #0284c7)"
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import { Card, Stack, Text, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
