const conditionEmojiMap: Record<string, string> = {
  sunny: '☀️',
  clear: '☀️',
  cloudy: '☁️',
  overcast: '☁️',
  'partly cloudy': '⛅',
  'mostly cloudy': '🌥️',
  rainy: '🌧️',
  rain: '🌧️',
  stormy: '⛈️',
  storm: '⛈️',
  thunderstorm: '⛈️',
  snowy: '❄️',
  snow: '❄️',
  foggy: '🌫️',
  fog: '🌫️',
  windy: '💨',
  hail: '🌨️',
  drizzle: '🌦️',
  mist: '🌁',
};

function getConditionEmoji(condition: string): string {
  const key = condition.toLowerCase().trim();
  if (conditionEmojiMap[key]) return conditionEmojiMap[key];
  for (const [k, v] of Object.entries(conditionEmojiMap)) {
    if (key.includes(k)) return v;
  }
  return '🌡️';
}

